/**
 * @name Reflected XSS via HTTP request parameters written to response
 * @description User input from HTTP requests flows to HTTP response output without sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/reflected-xss-keycloak
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // PrintWriter.write/println
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ServletResponse output stream
    exists(MethodCall mc |
      mc.getMethod().hasName("write") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Response builder entity
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.ws.rs.core", "Response$ResponseBuilder") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module XssFlow = TaintTracking::Global<XssConfig>;
import XssFlow::PathGraph

from XssFlow::PathNode source, XssFlow::PathNode sink
where XssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS: user input flows to HTTP response output from $@.", source.getNode(), "user input"

/**
 * @name XSS in Keycloak server-side HTML generation - taint from request to HTML response
 * @description User input from HTTP requests flows to HTML response without encoding, focused on core server
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-server-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XssServerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // PrintWriter.write/println
    exists(MethodCall mc |
      mc.getMethod().hasName(["write", "println", "print"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Response.entity()
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.ws.rs.core", "Response$ResponseBuilder") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  // Only consider sources and sinks within the main services or quarkus packages
  predicate isBarrier(DataFlow::Node node) {
    // Filter out adapter and test code
    node.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.adapters%") or
    node.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.testsuite%") or
    node.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.client%") or
    // Filter out LDAP password operations (not XSS)
    node.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.storage.ldap%") or
    // Filter out build processors
    node.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.models.map.processor%")
  }
}

module XssServerFlow = TaintTracking::Global<XssServerConfig>;
import XssServerFlow::PathGraph

from XssServerFlow::PathNode source, XssServerFlow::PathNode sink
where XssServerFlow::flowPath(source, sink)
  and (
    // Focus on server-side keycloak packages
    sink.getNode().getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.services%") or
    sink.getNode().getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.quarkus%")
  )
select sink.getNode(), source, sink, "Server-side XSS: user input flows to HTTP response from $@.", source.getNode(), "user input"

/**
 * @name User input in HTML string concatenation in Keycloak services
 * @description User-controlled data used in string concatenation building HTML responses
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-html-concat-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module HtmlConcatConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // String concatenation where the result is returned as HTTP response entity
    exists(MethodCall responseCall |
      (
        responseCall.getMethod().hasName("entity") or
        responseCall.getMethod().hasName("ok")
      ) and
      responseCall.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.services%") and
      DataFlow::localFlow(sink, DataFlow::exprNode(responseCall.getAnArgument()))
    )
    or
    // Direct entity/ok calls in keycloak service classes
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      mc.getEnclosingCallable().getDeclaringType().getPackage().getName().matches("org.keycloak.services%") and
      sink.asExpr() = mc.getArgument(0)
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // HTML encoding calls are barriers
    exists(MethodCall mc |
      mc.getMethod().hasName(["encodeForHTML", "escapeHtml", "escapeXml", "htmlEscape", "sanitize", "encode"]) and
      node.asExpr() = mc
    )
  }
}

module HtmlConcatFlow = TaintTracking::Global<HtmlConcatConfig>;
import HtmlConcatFlow::PathGraph

from HtmlConcatFlow::PathNode source, HtmlConcatFlow::PathNode sink
where HtmlConcatFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTML injection: user input $@ flows to response entity without encoding.", source.getNode(), "user input"

/**
 * @name XSS in Keycloak error handler reflecting request data
 * @description KeycloakErrorHandler reflects exception message or request URI in HTML response
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-error-handler-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ErrorHandlerXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName("KeycloakErrorHandler") and
      (
        mc.getMethod().hasName("entity") or
        mc.getMethod().hasName("ok") or
        mc.getMethod().hasName(["write", "println", "print"])
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ErrorHandlerXssFlow = TaintTracking::Global<ErrorHandlerXssConfig>;
import ErrorHandlerXssFlow::PathGraph

from ErrorHandlerXssFlow::PathNode source, ErrorHandlerXssFlow::PathNode sink
where ErrorHandlerXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "KeycloakErrorHandler XSS: request data $@ reflected without encoding.", source.getNode(), "user input"

/**
 * @name WelcomeResource createWelcomePage - request parameter reflected in HTML without encoding
 * @description Direct XSS: form parameter 'stateChecker' or similar reflected in HTML page without encoding 
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-welcome-param-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module WelcomeParamConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Request parameters, headers, form data from WelcomeResource or QuarkusWelcomeResource
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      mc.getMethod().hasName(["getFirstValue", "getFormParameters", "getDecodedFormParameters",
                               "getParameter", "getHeader", "getFormData",
                               "getQueryParameters", "getPathParameters"]) and
      source.asExpr() = mc
    )
    or
    // @FormParam, @QueryParam annotated parameters in WelcomeResource methods
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      p.getAnAnnotation().getType().hasQualifiedName("javax.ws.rs", ["FormParam", "QueryParam", "PathParam", "HeaderParam"]) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Response entity in WelcomeResource
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      mc.getMethod().hasName("entity") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // String used to build HTML response  
    exists(StringLiteral sl |
      sl.getEnclosingCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      sink.asExpr() = sl
    )
  }
}

module WelcomeParamFlow = TaintTracking::Global<WelcomeParamConfig>;
import WelcomeParamFlow::PathGraph

from WelcomeParamFlow::PathNode source, WelcomeParamFlow::PathNode sink
where WelcomeParamFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "WelcomeResource: request param $@ flows to HTML response without encoding.", source.getNode(), "user input"

/**
 * @name AdvancedMessageFormatterMethod returns unescaped HTML via message format arguments
 * @description Message formatter processes user-controlled data through toString() and format() without HTML encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-message-formatter-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module MessageFormatterXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // The exec() return value (a formatted string) used in template rendering
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasName(["AdvancedMessageFormatterMethod", "MessageFormatterMethod"]) and
      sink.asExpr() = mc
    )
    or
    // Message arguments passed to format()
    exists(MethodCall mc |
      mc.getMethod().hasName("format") and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["escapeHtml", "encodeForHTML", "htmlSpecialChars", "sanitize"]) and
      node.asExpr() = mc
    )
  }
}

module MessageFormatterXssFlow = TaintTracking::Global<MessageFormatterXssConfig>;
import MessageFormatterXssFlow::PathGraph

from MessageFormatterXssFlow::PathNode source, MessageFormatterXssFlow::PathNode sink
where MessageFormatterXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Message formatter XSS: user input $@ flows to format() output without HTML encoding.", source.getNode(), "user input"

/**
 * @name Keycloak WelcomeResource and QuarkusWelcomeResource - POST form data reflected in HTML without encoding
 * @description The username/password submitted during initial admin bootstrap flows into HTML response without HTML encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/keycloak-welcome-form-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module WelcomeFormConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // POST form params annotated with @FormParam in WelcomeResource/QuarkusWelcomeResource 
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      source.asParameter() = p
    )
    or
    // getFirstValue, getFormParameters calls within WelcomeResource  
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      mc.getMethod().hasName(["getFirstValue", "getDecodedFormParameters", "get", "getParameter"]) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Response entity or HTML string building within WelcomeResource methods
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      (
        mc.getMethod().hasName("entity") or
        mc.getMethod().hasName("ok")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // String building - any usage that will be used in HTML output
    exists(AddExpr add |
      add.getEnclosingCallable().getDeclaringType().hasName(["WelcomeResource", "QuarkusWelcomeResource"]) and
      sink.asExpr() = add.getAnOperand()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    exists(MethodCall mc |
      mc.getMethod().hasName(["escapeHtml", "encodeForHTML", "htmlEscape", "sanitize"]) and
      node.asExpr() = mc
    )
  }
}

module WelcomeFormFlow = TaintTracking::Global<WelcomeFormConfig>;
import WelcomeFormFlow::PathGraph

from WelcomeFormFlow::PathNode source, WelcomeFormFlow::PathNode sink
where WelcomeFormFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "WelcomeResource form param XSS: $@ flows to HTML output without encoding.", source.getNode(), "form input"
